### Proxy Validation Tests
```rust
#[test]
fn test_proxy_valid_url() {
    let proxy = ProxyDef { url: "http://proxy.example.com:8080".into(), .. };
    let result = validate_proxy(&proxy);
    assert!(result.is_empty());
}

#[test]
fn test_proxy_missing_port() {
    let proxy = ProxyDef { url: "http://proxy.example.com".into(), .. };
    let result = validate_proxy(&proxy);
    assert!(result.iter().any(|r| r.message.contains("port")));
}

#[test]
fn test_proxy_invalid_url() {
    let proxy = ProxyDef { url: "not-a-url".into(), .. };
    let result = validate_proxy(&proxy);
    assert!(result.iter().any(|r| r.severity == Severity::Error));
}

#[test]
fn test_proxy_missing_env_var() {
    // Proxy with username_env pointing to unset var
    std::env::remove_var("TEST_PROXY_USER");
    let proxy = ProxyDef { 
        auth: Some(Auth { username_env: Some("TEST_PROXY_USER".into()), .. }),
        ..
    };
    let result = validate_proxy(&proxy);
    assert!(result.iter().any(|r| r.message.contains("not set")));
}

#[test]
fn test_proxy_plaintext_credentials_warning() {
    let proxy = ProxyDef {
        auth: Some(Auth { username: Some("user".into()), password: Some("pass".into()), .. }),
        ..
    };
    let result = validate_proxy(&proxy);
    assert!(result.iter().any(|r| r.severity == Severity::Warning && r.message.contains("plaintext")));
}

#[test]
fn test_duplicate_proxy_ids() {
    let proxies = vec![
        ProxyDef { id: "proxy1".into(), .. },
        ProxyDef { id: "proxy1".into(), .. },
    ];
    let result = validate_proxies(&proxies);
    assert!(result.iter().any(|r| r.message.contains("duplicate")));
}
```

